      'Nullable(String)',
      'LowCardinality(String)',
      'LowCardinality(Nullable(String))',
      'Array(String)',
      'Array(UInt32)',
      'Array(Array(String))',
      'Map(String, UInt64)',
      'Tuple(String, UInt32)',
      'Tuple(String, Array(UInt32))',
      'Array(Tuple(String, Array(UInt32)))',
      "Enum8('a' = 1, 'b' = 2)",
      "Enum16('active' = 1, 'inactive' = 2, 'deleted' = 3)",
